module top_module (
    input clk,
    input reset,
    input up,
    output [2:0] count );reg [2:0] count_reg;

    always @(posedge clk) begin
        if (reset)
            count_reg <= 3'b000;
        else if (up)
            count_reg <= count_reg + 1;
        else
            count_reg <= count_reg - 1;
    end

    wire cnt_inv = count_reg;
    assign count = cnt_inv;

endmodule
